  <g font-family="sans-serif">
    <rect x="100" y="58" width="500" height="68" rx="10" fill="#e84142" opacity="0.85"/>
    <text x="350" y="97" fill="#fff" font-size="15" font-weight="700" text-anchor="middle">Öffentliche C-Chain — Prämien &amp; Promo-NFTs</text>
